#!/usr/bin/env node
/**
 * post-visual-diff.mjs — read manifest.json from OUT_DIR, build the comment
 * body referencing PNG URLs on the `pr-screenshots` orphan branch, and print
 * to stdout. The workflow step that calls this is responsible for committing
 * the PNGs to refs/heads/pr-screenshots and then posting / updating the
 * marker-tagged PR comment.
 *
 * Env:
 *   OUT_DIR        where manifest.json + PNGs live
 *   REPO           owner/repo (e.g. vivekchand/clawmetry)
 *   PR_NUMBER      PR number
 *   HEAD_SHA       head commit sha (short or full)
 *   ALWAYS_POST    "1" to render even if no diffs flagged (default: "0")
 */
import fs from "node:fs/promises";
import path from "node:path";

const OUT_DIR = process.env.OUT_DIR || "screenshots";
const REPO = process.env.REPO;
const PR = process.env.PR_NUMBER;
const SHA = (process.env.HEAD_SHA || "").slice(0, 12);
const ALWAYS_POST = process.env.ALWAYS_POST === "1";

if (!REPO || !PR || !SHA) {
  console.error("REPO, PR_NUMBER, HEAD_SHA env required");
  process.exit(2);
}

// Use the raw.githubusercontent.com URL for inline image rendering on
// public repos. Falls back gracefully on private repos (logged-in reviewers
// still see the blob view via the linked tree URL).
const rawBase = `https://raw.githubusercontent.com/${REPO}/pr-screenshots/pr/${PR}/${SHA}`;
const treeUrl = `https://github.com/${REPO}/tree/pr-screenshots/pr/${PR}/${SHA}`;

const manifest = JSON.parse(
  await fs.readFile(path.join(OUT_DIR, "manifest.json"), "utf8")
);
const flagged = manifest.filter((m) => m.hasDiff);

if (flagged.length === 0 && !ALWAYS_POST) {
  const body = [
    "## Visual diff",
    "",
    "No visual changes detected on the captured dashboard tabs (threshold 1%).",
    "",
    `Folder: [pr/${PR}/${SHA}](${treeUrl}) · also attached as workflow artefact.`,
    "",
    "_Generated by visual-diff bot. Pixel diffs >1% flagged; eyeball the table before merging._",
  ].join("\n");
  process.stdout.write(body);
  process.exit(0);
}

const rows = manifest
  .map((m) => {
    const label = `${m.view} ${m.tab}`;
    const before = `${rawBase}/${m.view}__${m.slug}__before.png`;
    const after = `${rawBase}/${m.view}__${m.slug}__after.png`;
    const diff = `${rawBase}/${m.view}__${m.slug}__diff.png`;
    const flag = m.hasDiff ? " ⚠️" : "";
    const err = m.baseOk && m.headOk ? "" : " · render-error";
    const pct = `${(m.diffPct * 100).toFixed(2)}%`;
    return `| ${label}${flag}${err} | [before](${before}) | [after](${after}) | [diff](${diff}) · ${pct} |`;
  })
  .join("\n");

const summary =
  flagged.length === 0
    ? "No flagged differences (running with ALWAYS_POST=1)."
    : `${flagged.length} of ${manifest.length} comparison(s) flagged (>1% pixel diff).`;

const body = [
  "## Visual diff",
  "",
  `Comparing \`${SHA}\` (head) against the PR base branch.`,
  "",
  summary,
  "",
  "| View | Before | After | Diff |",
  "|---|---|---|---|",
  rows,
  "",
  `Folder: [pr/${PR}/${SHA}](${treeUrl}). Full PNGs also attached as a workflow artefact.`,
  "",
  "_Generated by visual-diff bot. Pixel diffs >1% flagged; eyeball the table before merging. This check is **non-blocking** — fail = bot bug, not a code problem._",
].join("\n");

process.stdout.write(body);
